        for dep in sorted(deps):
            print(f"  -> {dep}")
    else:
        print(f"{pkg}: (leaf node)")

print(f"\n=== All Internal Packages (total: {len(all_packages)}) ===")
for pkg in sorted(all_packages):
    print(pkg)

# Better topological sort - dependencies before dependents
def topo_sort_correct(graph, all_nodes):
    result = []
    visited = set()
    visiting = set()

    def dfs(node):
        if node in visited:
            return
        if node in visiting:
            return  # cycle, skip

        visiting.add(node)

        # Visit dependencies first
        for dep in sorted(graph.get(node, set())):
            if dep in all_nodes:
