#!/usr/bin/env python3
import os
import re
from collections import defaultdict, deque

# Normalize import path by removing module prefix
def normalize_import(imp):
    imp = imp.strip().strip('"').strip("'")
    if imp.startswith('go.flipt.io/flipt/'):
        imp = imp[len('go.flipt.io/flipt/'):]
    return imp if imp else None

# Is this an internal flipt package?
def is_internal(pkg):
    # Internal means it's within the flipt module
    return pkg.startswith('internal/') or pkg.startswith('rpc/') or pkg == 'errors'

# Extract imports from a single Go file
def extract_imports_from_file(filepath):
    imports = set()
    try:
        with open(filepath, 'r') as f:
            content = f.read()
            # Find import block
            import_match = re.search(r'import\s*\((.*?)\)', content, re.DOTALL)
            if import_match:
                import_block = import_match.group(1)
                for line in import_block.split('\n'):
                    line = line.strip()
                    if line and not line.startswith('//'):
                        if '"' in line:
                            match = re.search(r'"([^"]+)"', line)
                            if match:
                                imp = match.group(1)
                                norm = normalize_import(imp)
                                if norm and is_internal(norm):
                                    imports.add(norm)
            # Also check for single imports
            for match in re.finditer(r'^\s*import\s+"([^"]+)"', content, re.MULTILINE):
                imp = match.group(1)
                norm = normalize_import(imp)
                if norm and is_internal(norm):
                    imports.add(norm)
    except:
        pass
    return imports

# Get all Go files in a directory
def get_go_files(directory):
    go_files = []
    if os.path.isdir(directory):
        for file in os.listdir(directory):
            if file.endswith('.go'):
                go_files.append(os.path.join(directory, file))
    return go_files

# Get internal imports for a package
def get_package_imports(pkg_path):
    full_path = os.path.join('/workspace', pkg_path)
    imports = set()

    if not os.path.isdir(full_path):
        return imports

    for go_file in get_go_files(full_path):
        file_imports = extract_imports_from_file(go_file)
        imports.update(file_imports)

    # Remove self-imports
    imports.discard(pkg_path)

    return imports

# Main dependency graph building
def build_dependency_graph(start_package):
    visited = set()
    queue = deque([start_package])
    graph = defaultdict(set)  # pkg -> set of imports (dependencies)

    while queue:
        pkg = queue.popleft()
        if pkg in visited:
            continue
        visited.add(pkg)

        imports = get_package_imports(pkg)
        graph[pkg] = imports

        for imp in imports:
            if imp not in visited:
                queue.append(imp)

    return graph, visited

# Topological sort using DFS (dependencies first)
def topo_sort_dfs(graph, all_nodes):
    result = []
    visited = set()
    visiting = set()

    def dfs(node):
        if node in visited:
            return
        if node in visiting:
            return  # cycle, skip

        visiting.add(node)

        # Visit dependencies first (things this node depends on)
        for dep in sorted(graph.get(node, set())):
            if dep in all_nodes:
                dfs(dep)

        visiting.remove(node)
        visited.add(node)
        result.append(node)

    # Start DFS from all nodes
    for node in sorted(all_nodes):
        if node not in visited:
            dfs(node)

    return result

# Start from evaluation server
start_pkg = 'internal/server/evaluation'
graph, all_packages = build_dependency_graph(start_pkg)

print(f"=== Dependency Graph (Internal Only) ===")
for pkg in sorted(all_packages):
    deps = graph.get(pkg, set())
    if deps:
        print(f"{pkg}:")
        for dep in sorted(deps):
            print(f"  -> {dep}")
    else:
        print(f"{pkg}: (leaf node - no internal dependencies)")

print(f"\n=== All Internal Packages (total: {len(all_packages)}) ===")
for pkg in sorted(all_packages):
    print(pkg)

# Topological sort
sorted_pkgs = topo_sort_dfs(graph, all_packages)

print(f"\n=== Topological Order (dependencies before dependents) ===")
for i, pkg in enumerate(sorted_pkgs, 1):
    print(f"{i}. {pkg}")

EOF

